//vip.opstream12.com/20250301/25590_f220707c/index.m3u8"}]}],"time":"92 Phút","description":"Từng là đặc vụ chính phủ nổi tiếng với khả năng tàng hình, Jack Cole hiện là thám tử cảnh sát Los Angeles. Khi hàng loạt vụ giết người kinh hoàng xảy ra ở khu vực tàu điện ngầm, Cole được giao nhiệm vụ này cùng với người đồng nghiệp có tài ăn nói cứng rắn Jim Campbell. Mặc dù hai người đàn ông xung đột, nhưng họ dần dần trở thành đối tác hiệu quả khi phát hiện ra một âm mưu liên quan đến các vụ giết người, cũng liên quan đến khủng bố và tội phạm có tổ chức.","tmdb":{"type":"movie","id":"9625","season":null,"vote_average":5.4,"vote_count":415},"modified":"2025-03-02T09:01:32.000Z","_image_preserved":true},{"id":"67c2bde096e9a5c7a692a114","_id":"67c2bde096e9a5c7a692a114","title":"Môn Tiền Bảo Địa","origin_name":"100 Yards","slug":"mon-tien-bao-dia","year":2024,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"},{"id":"620f3d2b91fa4af90ab697fe","name":"Chính kịch","slug":"chinh-kich"}],"country":[{"id":"62093063196e9f4ab6b448b8","name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"100.Yards.2023.1080p.BluRay.DD5.1.x264-SPHD-Vietsub","link_embed":"https://vip.opstream12.com/share/6e18b12a82c40871803b88fa42cc1a20","link_m3u8":"https://vip.opstream12.com/20250301/25583_6e18b12a/index.m3u8"}]}],"time":"108 Phút","description":"Môn tiền bảo địa - 100 Yards (2024) Bối cảnh phim diễn ra tại Thiên Tân, Trung Quốc vào những năm 1920. Sau khi một võ sư nổi tiếng qua đời, hai học trò của ông trở thành đối thủ không đội trời chung để tranh giành quyền thừa kế võ đường. Một bên là Tề, đại đệ tử và người thừa kế được kỳ vọng, trong khi bên kia là Thẩm, con trai của sư phụ, người lẽ ra không theo nghiệp võ nhưng lại có đam mê mãnh liệt với nó. Cuộc tranh chấp được quyết định bằng võ đấu, nhưng kết quả chỉ làm tăng thêm mâu thuẫn. Khi những thách thức giữa họ ngày càng nhiều, các quy tắc truyền thống dần bị phá vỡ, gây chấn động cộng đồng võ thuật.","tmdb":{"type":"movie","id":"1122824","season":null,"vote_average":6.056,"vote_count":18},"modified":"2025-03-02T09:02:35.000Z","_image_preserved":true},{"id":"67c2bf6cc1dc148540b53dc7","_id":"67c2bf6cc1dc148540b53dc7","title":"Rosetta","origin_name":"Rosetta","slug":"rosetta","year":1999,"type":"single","genre":[{"id":"620f3d2b91fa4af90ab697fe","name":"Chính kịch","slug":"chinh-kich"}],"country":[{"id":"620a2378e0fc277084dfd972","name":"Pháp","slug":"phap"},{"id":"6246acafc78eb57bbfe35df6","name":"Bỉ","slug":"bi"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Rosetta.1999.1080p.BluRay.FLAC2.0.x264-PTer-Vietsub","link_embed":"https://vip.opstream12.com/share/f29ecfa692a4f9f9953f1cc2becfd19b","link_m3u8":"https://vip.opstream12.com/20250301/25601_f29ecfa6/index.m3u8"}]}],"time":"95 Phút","description":"Young, impulsive Rosetta lives a hard and stressful life as she struggles to support herself and her alcoholic mother. Refusing all charity, she is desperate to maintain a dignified job.","tmdb":{"type":"movie","id":"11489","season":null,"vote_average":7.181,"vote_count":320},"modified":"2025-03-02T08:59:07.000Z","_image_preserved":true},{"id":"67c2c0967cf9d8f91e870b6d","_id":"67c2c0967cf9d8f91e870b6d","title":"Kẻ Đầu Mối Pháp 2","origin_name":"French Connection II","slug":"ke-dau-moi-phap","year":1975,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"},{"id":"620a2249e0fc277084dfd2e5","name":"Hình Sự","slug":"hinh-su"},{"id":"62